// Filter to live-capable enabled RSS sources only.
// Business logic stays in the API — this node only filters.
// Hardened: wraps in try/catch to prevent 'Unknown error' crashes on empty/malformed API responses.
try {
  const input = $input.first();
  if (!input || !input.json) {
    console.warn('[rss-intake] No response from /sources endpoint — skipping.');
    return [];
  }
  const liveEnabled = input.json.liveIntakeEnabled;
  if (!liveEnabled) {
    console.log('[rss-intake] Live intake kill switch is OFF — skipping all sources.');
    return [];
  }
  const sources = input.json.sources;
  if (!Array.isArray(sources)) {
    console.warn('[rss-intake] sources is not an array — skipping. Got:', typeof sources);
    return [];
  }
  const rss = sources.filter(s => s.type === 'rss' && s.enabled && s.liveCapable);
  return rss.map(s => ({ json: s }));
} catch (err) {
  console.error('[rss-intake] Filter error:', err.message || String(err));
  return [];
}
